/** Format mindstate guidance for AI prompts */
export function getMindstateGuidance(profiles: MindstateProfile[]): string {
  return profiles.map(ms => `Mindstate: ${ms.name} (${ms.approach} ${ms.motivation})
Goal: ${ms.goalToActivate}
Approach: ${ms.approachFraming}
Evoke: ${ms.feelingsToEvoke.join(", ")}
Avoid: ${ms.feelingsToAvoid.join(", ")}
Triggers: ${ms.triggers.join(" | ")}
Visual: ${ms.visualGuidance}
Tone: ${ms.copyTone}
Examples: ${ms.exampleHeadlines.join(" | ")}`).join("\n\n---\n\n");
}

export function getMindstateById(id: string): MindstateProfile | undefined {
  return MINDSTATE_PROFILES.find(ms => ms.id === id);
}

export function getMindstatesByApproach(approach: "cautious" | "optimistic"): MindstateProfile[] {
  return MINDSTATE_PROFILES.filter(ms => ms.approach === approach);
}

export function getMindstatesByMotivation(motivation: string): MindstateProfile[] {
  return MINDSTATE_PROFILES.filter(ms => ms.motivation === motivation);
}